mapper.select:
SELECT COUNT(DISTINCT credit_account_id)
FROM card_transactions
WHERE status = 'POSTED'
  AND billing_status = 'UNBILLED'
  AND posted_at >= #{periodStartInclusive}
  AND posted_at < #{periodEndExclusive}

SELECT DISTINCT credit_account_id
FROM card_transactions
WHERE status = 'POSTED'
  AND billing_status = 'UNBILLED'
  AND posted_at >= #{periodStartInclusive}
  AND posted_at < #{periodEndExclusive}
  AND MOD(CRC32(credit_account_id), #{shardCount}) = #{shardNo}
ORDER BY credit_account_id
